export const PAGES: LandingPage[] = [{ "slug": "automatiser-la-com-projet", "type": "produit", "meta": { "title": "Automatiser la com' projet", "description": "Bien communiquer c'est 50% du succès de vos projets. Mais ça prend un temps fou et on rentre souvent trop dans le détail. Découvrez l'email \"bilan de santé\" qui partage juste le bon niveau d'information, automatiquement, une fois par semaine.", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "Email \"bilan de santé\" : Automatisez la communication projet", "subtitle": "Bien communiquer, c'est 50% du succès de vos projets. Mais ça prend un temps fou et on rentre souvent trop dans le détail. Découvrez l'email \"bilan de santé\" qui partage juste le bon niveau d'information, automatiquement, une fois par semaine.", "primaryCta": { "label": "Je veux une démo", "href": "/fr/meetings-pages" }, "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/664b24837fe62a131250a50c_3413e379b45a09d99b27d62ecb0a20c7_Control%20tower%20email%20FR%20%28screen%29.webp", "imageAlt": "Bilan de santé" }, { "type": "intro", "title": "Vous n'entendrez bientôt plus ces phrases ...", "subSections": [{ "title": "Ajoutez les sponsors sur vos projets", "body": "<p>Ajoutez les sponsors sur vos projets et ils recevront le bilan de santé de tous leurs projets, le lundi matin par email. <br/><br/>Aussi simple que ça.</p>" }] }, { "type": "feature-split", "reversed": false, "title": "Ajoutez les sponsors sur vos projets", "body": "Ajoutez les sponsors sur vos projets et ils recevront le bilan de santé de tous leurs projets, le lundi matin par email. <br/><br/>Aussi simple que ça.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/6645f73c0195b1d0919ff025_Block%20-%20people%20involved%20screen.webp", "imageAlt": "Personnes impliquées" }] }, { "slug": "budget", "type": "produit", "meta": { "title": "Budget", "description": "Lorsqu'en Codir il faut prioriser les 125 projets du portfolio, c'est un peu dur de s'y retrouver. Tout le monde y va de ses projets \"urgentissimes\" et remplir la roadmap des prochains trimestres se fait finalement en fonction de celui qui parle le plus fort ou celui le plus copain avec le DG", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "Le suivi budgétaire de vos projets", "subtitle": "Le budget, c’est un peu le GPS des projets du portfolio. Il permet de maintenir le cap, tout en évitant les dérives. C’est aussi un indicateur qui témoigne de la bonne avancée des projets. Gardez un œil dessus pour mieux contrôler les dépenses !", "primaryCta": { "label": "Je veux une démo", "href": "/fr/meetings-pages" }, "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66fbefc6521c27b9a3836ebc_Budget%20screen.webp", "imageAlt": "Budget page" }, { "type": "intro", "title": "Un suivi facile sans prise de tête", "body": "<p>Avoir une photo en temps réel est essentiel à chaque phase du projet pour savoir où vous en êtes. Cela permet de faire son suivi budgétaire facilement et de le présenter à ses supérieurs en quelques clics directement depuis AirSaas.</p>" }, { "type": "feature-split", "reversed": false, "title": "Un cadrage simplifié avec un budget détaillé", "body": "Pour chaque projet en phase de cadrage, vos chefs de projets ajoutent plusieurs lignes de dépenses détaillées et classées en CAPEX et en OPEX pour anticiper les coûts et objectiver l’étape de validation.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66f323015aaa9b92b42e6397_ADD%20EXPENSES%20LINES.webp", "imageAlt": "ADD EXPENSES" }, { "type": "feature-split", "reversed": false, "title": "Des vues consolidées à partager facilement", "body": "Parce que le visuel, ça compte, vous pouvez enfin choisir le groupe de projets qui vous intéresse pour basculer sur la vue budgétaire et ainsi, obtenir une image plus parlante grâce aux graphiques. Ces vues consolidées sont facilement partageables avec les membres du COMEX lors des réunions.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66f401cfa1c5e13cc3adf9a3_Budget%20graphics%20screen.webp", "imageAlt": "Des vues consolidées à partager facilement" }, { "type": "feature-split", "reversed": true, "title": "Prenez en compte le coût humain des projets", "body": "Le coût humain est le plus important poste de dépense dans les budgets. Qu’il soit interne ou externe, ne l’oublions pas. Sur AirSaas renseigner les TJM des équipes et découvrez le coût humain de vos projets.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66fbf0caa595317d71d53652_Teams%20budget.webp", "imageAlt": "Prenez en compte le coût humain des projets" }, { "type": "feature-split", "reversed": false, "title": "Des indicateurs pour piloter sereinement", "body": "Suivre les budgets project, c’est bien, mais pour cela il faut pouvoir faire confiance à la “fraicheur” des données renseignées. Pour chaque ligne de dépense, la date de dernière mise à jour est visible. AirSaas vous propose également un indicateur de fiabilité pour un contrôle renforcé !", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66fbf0fe7414e2b3845dbb9f_Des%20indicateurs.webp", "imageAlt": "Des indicateurs pour piloter sereinement" }, { "type": "feature-split", "reversed": true, "title": "Garder un œil sur les dépenses additionnelles", "body": "Difficile de prévoir toutes les dépenses nécessaires lors de la création du budget en phase de cadrage ! Si de nouvelles dépenses apparaissent lors de la phase d’exécution, pas de souci ! Vous pouvez les ajouter à celles qui étaient déjà planifiées pour plus d’agilité, tout en gardant une trace de ce qui avait été validé lors du cadrage !", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66fbf13616fcb88f01125d9b_Feed%20budget.webp", "imageAlt": "Garder un œil sur les dépenses additionnelles" }, { "type": "feature-split", "reversed": false, "title": "Une personnalisation des dépenses adaptée à votre organisation", "body": "AirSaas s’adapte à tous les types d’organisations pour que votre suivi budgétaire soit encore plus compréhensible ! Pour chaque dépense, vos chefs de projets peuvent renseigner un axe analytique. Vous pouvez ensuite accéder aux graphiques consolidés des dépenses projets par axe et ainsi découvrir les principaux postes de coûts. Si les axes analytiques proposés ne sont pas suffisants, pas de problème, vous pouvez ajouter les vôtres en un clic.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66f327d0f3cd55dfdb3ad2d5_Analytical%20axes.webp", "imageAlt": "Analytical axes" }, { "type": "faq", "title": "Questions", "titleHighlight": "fréquentes", "items": [{ "question": "Est-il possible de modifier le budget planifié ?", "answer": "Oui… mais non. Une fois que le projet est validé au cadrage, la somme entrée en planifié ne change plus. Cependant, vous pouvez ajouter des nouvelles lignes de dépense si besoin. Un tag “modifié” apparaîtra alors sur la somme totale en planifié." }, { "question": "Qu’est-ce qui est visible en vues consolidées ?", "answer": "La liste des projets avec leurs détails et les dates de mise à jour, les sommes Opex et Capex, et la répartition du budget par axes analytiques." }] }] }, { "slug": "capacity-planning", "type": "produit", "meta": { "title": "Capacity Planning : planifiez la capacité de vos équipes", "description": "Grâce à la vue Capacitaire, vous aurez les bases d’une discussion pragmatique pour répondre à la question : est-on capable de faire les projets prévus cette année, ce semestre, ce trimestre ?", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "Capacitaire : Pouvons-nous réellement faire ces projets ?", "subtitle": "Grâce à la vue Capacitaire, vous aurez les bases d’une discussion pragmatique pour répondre à la question : est-on capable de faire les projets prévus cette année, ce semestre, ce trimestre ?", "primaryCta": { "label": "Je veux une démo", "href": "/fr/meetings-pages" }, "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66334ee7bcfcb0aa45802537_Capacity%20screen.webp", "imageAlt": "Capacity Marketing" }, { "type": "intro", "title": "Une réponse à toutes vos questions", "body": "<ul><li>Pourrait-on faire plus de projets le prochain trimestre ?</li><li>Doit-on recruter ?</li><li>Quelle surcharge acceptons-nous d’avoir ?</li></ul><p><strong>N'avancez plus \"au feeling\", la vue Capacitaire vous aidera à répondre à ces questions, par équipe et sur l'ensemble de votre organisation.</strong></p>" }, { "type": "intro", "title": "Mise en place rapide, simple à maintenir dans le temps", "body": "<p>Mettre en place un capacitaire est souvent une démarche lourde et chronophage. Le maintenir dans le temps est mission impossible.<br/>Pour palier à ça nous avons pris le parti suivant :</p><p>Voici comment nous le concrétisons.</p>" }, { "type": "intro", "title": "Les Scénarios", "body": "<p>Ce qui limite le build c’est la capacité réelle des équipes à faire les projets. Comment montrer dynamiquement et visuellement cette réalité au top management ?</p>", "subSections": [{ "title": "Trouvez le scénario qui fonctionne", "body": "<p>Agencez les projets et visualisez l’impact sur les équipes jusqu’à trouver le scénario que toutes sont en capacité de mener à bien.</p><p>‍</p><p>‍</p>" }] }, { "type": "intro", "subSections": [{ "title": "Sur l'échelle de temps qui fait sens : à la semaine, au mois, au trimestre, au semestre, au PI", "body": "<p>Tenir un capacitaire à la semaine nécessite que l'ensemble des tâches commencent et terminent dans un intervalle d'une semaine. Chez AirSaas, nous souhaitons vous apporter une vue plus macro, plus proche de vos réalités. Vous pouvez choisir l'échelle de temps de capacitaire : au trimestre, au semestre ou en fonction de la durée de votre PI.</p>" }] }, { "type": "intro", "title": "Une vue simple et actionnable", "body": "<p>Visualisez en un clin d'oeil si vous êtes dans les clous... ou dans les choux. Grâce à cette vue vous avez les bases d'une discussion pragmatique pour prendre les décisions :</p><p>‍</p><p>‍</p>" }, { "type": "feature-split", "reversed": false, "title": "Estimation du temps nécessaire à la tâche au livrable", "body": "Pas besoin de rentrer dans le détail micro. Une taille de t-shirt à l'échelle du livrable suffit pour avoir une bonne estimation du temps nécessaire.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/6787bda3d16737c6ddb82fd5_Modal%20-%20Livrable.webp", "imageAlt": "Livrable" }, { "type": "feature-split", "reversed": true, "title": "Estimation des temps nécessaires et disponibles à la personne par équipe", "body": "Lorsque que vous allez configurer votre capacitaire, il est essentiel de se projeter sur le temps que l'on a disponible pour les projets (aka le build). Plutôt que le faire à la personne, nous vous proposons de le faire à l'échelle de l'équipe.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66334dad60affe8f9f6cf3db_Screen%20marketing%20temps.webp", "imageAlt": "Capacity Marketing team" }, { "type": "faq", "title": "Questions", "titleHighlight": "fréquentes", "items": [{ "question": "Comment je fais pour prioriser si j'ai des compétences différentes dans mon équipe ?", "answer": "Tout l'enjeu est de bien découper les équipes en regroupant les personnes aux compétences homogènes. Par exemple : marketing data, sécurité IT, IT data, etc." }, { "question": "Les t-shirt sizing sont-ils personnalisables ?", "answer": "Oui ! Et si vous avez une idée plus précise du temps nécessaire pour un livrable, vous pouvez aussi l'écrire." }, { "question": "Comment fixer la temporalité (trimestre, mois, PI) ?", "answer": "A vous de choisir ! Ce qui semble bien marcher, c'est le trimestre, car on se cale sur la temporalité de l'organisation (finance, commerciale)." }, { "question": "Si j'ai des projets ou features qui dépassent cette temporalité, comment faire ?", "answer": "On découpe ! Vous avez bien sûr en tête le dernier projet ERP ou CRM qui a duré 18 mois. Nous vous proposons de le découper en livrables qui permettent de mesurer l'avancement et de reprioriser ce qui doit être fait." }, { "question": "Est-ce que ça suffit pour un capacitaire ?", "answer": "Oui, pour savoir ce qu'il possible de faire au niveau macro. C'est ce qu'il manque souvent au top management pour prioriser. Ensuite, vous pouvez faire un capacitaire à la personne à 2 ou 3 mois, mais pas plus." }, { "question": "J'ai certaines personnes comme les \"architectes IT\" qui n'ont pas d'équipe à proprement parler. Comment intégrer cela dans AirSaas ?", "answer": "Pas de souci : vous créez une équipe pour l'architecte IT." }] }] }, { "slug": "priorisation-par-equipes", "type": "produit", "meta": { "title": "Priorisation par équipes", "description": "Lorsqu'en Codir il faut prioriser les 125 projets du portfolio, c'est un peu dur de s'y retrouver. Tout le monde y va de ses projets \"urgentissimes\" et remplir la roadmap des prochains trimestres se fait finalement en fonction de celui qui parle le plus fort ou celui le plus copain avec le DG", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "La priorisation des projets, par équipe en demande", "subtitle": "Lorsqu'en Codir il faut prioriser les 125 projets du portfolio, c'est un peu dur de s'y retrouver. Tout le monde y va de ses projets \"urgentissimes\", et remplir la roadmap des prochains trimestres se fait finalement en fonction de celui qui parle le plus fort ou celui le plus copain avec le DG.", "primaryCta": { "label": "Je veux une démo", "href": "/fr/meetings-pages" }, "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/663d07b7eeea99ee02f71c97_Prioritization%20per%20team%20ppt.webp", "imageAlt": "Priorisation team" }, { "type": "intro", "title": "La manière la plus simple d'y voir clair", "body": "<p>Réduisez la complexité en demandant à chaque responsable d'équipe de prioriser de son côté. Impossible de mettre 5 projets en Top 1 :chacun a une priorité de 1 à 100 pour enfin savoir ce qui est vraiment prioritaire.</p>" }, { "type": "feature-split", "reversed": false, "title": "Chaque équipe définie ses prios", "body": "Demandez aux responsables de prioriser parmi les projets dont son équipe est à l'origine. Deux projets ne peuvent pas avoir la même priorité. Une fois prêts, ils valident leur choix.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/663d07a346b12e77e37ddd72_Prioritization%20per%20team%20ppt%20d%26d.webp", "imageAlt": "Priorisation options" }, { "type": "feature-split", "reversed": true, "title": "Soyez notifié lorsque les priorités changent", "body": "Gardez vos équipes alignées sur ce qui est prioritaire. Lorsqu'une priorité change, toute personne participant aux projets reçoit l'information.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/663d07e315eb20b766f71fb9_Prioritization%20per%20team%20notification.webp", "imageAlt": "Priorisation notifications" }, { "type": "feature-split", "reversed": false, "title": "Organisez la roadmap de façon éclairée", "body": "Sur vos porfolios, affichez la priorité de chaque projet validée par l'équipe en demande. Cette information, couplée aux autres données de priorisation (budget, criticité, etc.) vous permet de faire des choix éclairés.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/6646051756191ce3dc501429_Portfolio%20project%20priority.webp", "imageAlt": "Portfolio project priority" }, { "type": "faq", "title": "Questions", "titleHighlight": "fréquentes", "items": [{ "question": "Comment je peux \"forcer\" un directeur à prioriser ?", "answer": "C'est assez simple : si le projet n'a pas de priorisation, il n'apparait pas comme priorisé par le métier dans la roadmap. Ça aide :)" }, { "question": "Chaque directeur peut prioriser ses projets, mais comment priorise-t-on les projets en transverse ?", "answer": "Pour pouvoir prioriser en transverse il faut trois choses. Que chaque responsable priorise ses besoins. Que la définition de ce qui est vital pour l'organisation soit partagée entre tous. D'un estimatif du temps homme et du gain potentiel de chaque projet. Cette fonctionnalité s'occupe du premier point." }, { "question": "Si on repriorise en cours de route comment ça se passe ?", "answer": "Pas de souci : tout est transparent. Vous pouvez reprioriser en expliquant à tout le monde les raisons" }] }] }, { "slug": "reporting-projet", "type": "produit", "meta": { "title": "Reporting projet", "description": "Le reporting projet est essentiel pour créer de l'adhésion et s'assurer que les projets ne dérapent pas, impliquer les sponsors, avoir des décisions éclairées prises rapidement, des risques adressés dans le timing imparti.", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "Découvrez enfin le plaisir du reporting projet", "subtitle": "Le reporting projet est essentiel pour créer de l'adhésion et s'assurer que les projets ne dérapent pas, impliquer les sponsors, avoir des décisions éclairées prises rapidement, des risques adressés dans le timing imparti. Mais disons la vérité : il est vécu comme une corvée par ceux qui le produisent et n'est jamais lu par ceux qui le reçoivent. Dommage... Découvrez comment nous avons craqué le problème.", "primaryCta": { "label": "Je veux une démo", "href": "/fr/meetings-pages" }, "imageAlt": "" }, { "type": "intro", "title": "Prenons de la hauteur", "body": "<p>Voici les 3 principales raisons pour lesquelles le reporting projet ne fonctionne pas dans les organisations :</p><ul><li><strong>1 •</strong><strong>Pas le bon niveau de d'abstraction</strong> : trop précis, tout le monde est perdu. Trop macro il n'apporte pas de valeur. Il faut trouver le juste milieu.</li><li><strong>2 •</strong> <strong>Trop chronophage</strong> : si le responsable passe 3 jours par mois à chercher et consolider les informations il ne tiendra pas sur la durée.</li><li><strong>3 •</strong> <strong>Chacun son format</strong> : si tous les reportings sont différents d'un projet à un autre, leur lecture devient trop compliquée.</li></ul><p><strong>Le reporting doit être homogène, clair, rapide à produire.</strong></p>" }, { "type": "intro", "title": "Plus besoin d'aller à la pêche aux informations", "body": "<p>Sur AirSaas, passez un deal avec vos chefs de projets : \"ce projet doit être à jour toutes les 2 semaines, le jeudi\". On s'occupe d'envoyer les rappels de mise à jour et vous donnons accès aux écrans de contrôle.</p>" }, { "type": "feature-split", "reversed": true, "title": "Une fiche projet homogène", "body": "Sur AirSaas, les fiches projets récapitulent les informations essentielles. Les éléments de cadrage (gains attendus, personnes impliquées, timeline des jalons, etc.) et les avancées d'exécution (progression, décisions à prendre, nouveaux risques, etc.). Pour plus de clarté, elles ont le même format d'un projet à l'autre.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66422c2062f8e4b86c4a3030_Presentation%20cadrage%20slide.webp", "imageAlt": "Flash reporting cadrage" }, { "type": "feature-split", "reversed": false, "title": "Un reporting généré en un clic", "body": "En un clic, générez le rapport flash aux couleurs de votre organisation, exportable au format PowerPoint ou PDF. Autant de temps gagné pour vous focaliser sur le coaching de vos chefs de projet et votre gouvernance.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/664602d0797ac9294687de0e_Portfolio-%20bt-presentation.webp", "imageAlt": "Report flash" }, { "type": "feature-split", "reversed": true, "title": "Un reporting customisable", "body": "Faites passer les bons messages dans votre rapport flash en épinglant les décisions à afficher, les points d'attention à aborder, les comptes rendu des dernières réunions, les derniers points succès de l'équipe, etc.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/664601436288365bdf5ec9bf_Presentation%20Execution%20screen.webp", "imageAlt": "Execution presentation" }, { "type": "faq", "title": "Questions", "titleHighlight": "fréquentes", "items": [{ "question": "Je peux customiser le reporting ?", "answer": "Oui ! Le rapport flash est personnalisable avec vos couleurs et votre logo. Vous pouvez ensuite choisir les éléments que vous voulez montrer." }, { "question": "On peut traduire le rapport flash automatiquement ?", "answer": "Oui : AirSaas utilise l'API de Deepl pour une traduction de qualité avec une niveau de sécurité au top." }, { "question": "Comment je rajoute les éléments de risques, de décisions ?", "answer": "C'est très simple : les chefs de projet ou Product Owners font remonter les décisions dans les compte-rendus de réunion depuis AirSaas. Ces décisions et risques sont automatiquement ajoutés dans le rapport flash. Vous pouvez bien sûr les enlever en un clic." }] }] }, { "slug": "traduction-one-click-avec-deepl", "type": "produit", "meta": { "title": "Traduction One Click avec Deepl", "description": "Présenter simplement ses projets, ses programmes et son portefeuille, c'est toujours un casse-tête dans les organisations multilingues. Un établissement aux US ? Votre maison mère en Allemagne ?", "ogImage": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/624550eb11b572a01480e4a1_Meta%20image.png" }, "sections": [{ "type": "hero", "title": "Le rapport flash désormais en multilingue sur AirSaas", "subtitle": "Présenter simplement ses projets, ses programmes et son portefeuille, c'est toujours un casse-tête dans les organisations multilingues. Un établissement aux US ? Votre maison mère en Allemagne ?Marre de passer des heures à sécuriser des traductions en amont de vos réunions ?", "primaryCta": { "label": "Je veux une démo", "href": "/fr/meetings-pages" }, "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66339df65cf2a6c1d863cf5f_copil-deepl-illustration.webp", "imageAlt": "deepL - AirSaas" }, { "type": "intro", "title": "Le rapport flash désormais enmultilingue sur AirSaas", "body": "<ul><li>Aligner toute une audience sur le sujet dont nous parlons.</li><li>Rappeler les ordres de grandeur d'un projet et les équipes à bord.</li><li>Donner du contexte temporel grâce aux jalons clés.</li><li>Engager la conversation sur l'essentiel, l'information de la santé, les décisions à prendre ou les points d'attention à partager.</li></ul><p><strong>C'est l'usage d'un rapport flash projet ou programme dans AirSaas. Découvrez la puissance de la traduction one-click intégrée avec Deepl.</strong></p>" }, { "type": "intro", "title": "Vos chefs de projets et PO ‍vont adorer", "body": "<p>Le bon pilotage s'appuie sur des cadrages précis, des remontées de risques contextualisées et des soumissions d'arbitrages éclairés. Quand toute l'énergie mise dans la construction d'un reporting de qualité est alourdie par le temps nécessaire à traduire et à maintenir des PowerPoints, vous n'aidez pas vos équipes</p><p>Voici comment nous le concrétisons.</p>" }, { "type": "intro", "subSections": [{ "title": "Plateforme multilingue à la maille utilisateur", "body": "<p>Dans AirSaas, chacun choisit sa langue d'utilisation de la solution. Anglais, Français et toute autre langue sur demande. Si besoin, notre équipe support parle couramment l'Anglais, l'Espagnol et le Français. Vous homogénéisez le reporting en conservant l'adaptabilité.</p>" }] }, { "type": "intro", "subSections": [{ "title": "Animer une réunion, aligner les parties prenantes, on parle le même language !", "body": "<p>Le mode rapport flash vous permet de construire en quelques clics le support de votre meeting. À vos couleurs et dans la langue du meeting à venir !</p>" }] }, { "type": "feature-split", "reversed": true, "title": "Écrivez dans votre langue maternelle, on s'occupe du reste", "body": "Écrivez tous vos contenus (compte-rendus, décisions à prendre, points d'attention, etc.) dans votre langue maternelle, AirSaas les rend accessibles à vos collègues dans leur langue maternelle à eux.", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/6646003be55efbd36750d4e9_post-deepl-illustration.webp", "imageAlt": "" }, { "type": "feature-split", "reversed": false, "title": "Animer une réunion, aligner les parties prenantes, on parle le même language !", "body": "Le mode rapport flash vous permet de construire en quelques clics le support de votre meeting. À vos couleurs et dans la langue du meeting à venir !", "imageAlt": "" }] }] as const;

